final String currentDeviceID = android.provider.Settings.Secure.getString(getContentResolver(), android.provider.Settings.Secure.ANDROID_ID);
_db.child(_uid).child("deviceID").addListenerForSingleValueEvent(new com.google.firebase.database.ValueEventListener() {
    @Override
    public void onDataChange(@NonNull com.google.firebase.database.DataSnapshot snapshot) {
        if (snapshot.exists()) {
            String savedDeviceID = snapshot.getValue(String.class);
            if (!currentDeviceID.equals(savedDeviceID)) {
                SketchwareUtil.CustomToast(getApplicationContext(), "Logged in on another device!", "#FFFFFF", 12, "#E53935", 60, SketchwareUtil.CENTER);
                com.google.firebase.auth.FirebaseAuth.getInstance().signOut();
                finishAffinity();
            }
        } else {
            _db.child(_uid).child("deviceID").setValue(currentDeviceID);
        }
    }
    @Override
    public void onCancelled(@NonNull com.google.firebase.database.DatabaseError error) {}
});

