            progressDialog.dismiss();
            taskSnapshot.getStorage().getDownloadUrl().addOnSuccessListener(new com.google.android.gms.tasks.OnSuccessListener<android.net.Uri>() {
                @Override
                public void onSuccess(android.net.Uri uri) {
                    String downloadUrl = uri.toString();
