                }
            });
        }
    })
    .addOnFailureListener(new com.google.android.gms.tasks.OnFailureListener() {
        @Override
        public void onFailure(@NonNull Exception e) {
            progressDialog.dismiss();
            SketchwareUtil.CustomToast(getApplicationContext(), e.getMessage(), "#FFFFFF", 12, "#E53935", 60, SketchwareUtil.CENTER);
        }
    })
    .addOnProgressListener(new com.google.firebase.storage.OnProgressListener<com.google.firebase.storage.UploadTask.TaskSnapshot>() {
        @Override
        public void onProgress(@NonNull com.google.firebase.storage.UploadTask.TaskSnapshot taskSnapshot) {
            double progress = (100.0 * taskSnapshot.getBytesTransferred()) / taskSnapshot.getTotalByteCount();
            progressDialog.setProgress((int) progress);
        }
    });

